assert.strictEqual(sum([1, 2, 3]), 6);  // was NaN before the fix
assert.strictEqual(sum([]), 0);
assert.strictEqual(sum([5]), 5);
assert.strictEqual(sum([-1, 1]), 0);
console.log("all tests passed");
```

